import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetimeimport urllib.parse# --- SAYFA AYARLARI ---st.set_page_config(page_title="Bostanlı Çözüm Bulut Paneli", layout="wide", page_icon="🏫")# --- GOOGLE SHEETS BAĞLANTISI ---URL = "https://docs.google.com/spreadsheets/d/18BUCCdmATfgHJB1JkM9-T5lhoUaSXes55iMgHVRpOP4/edit?usp=sharing"conn = st.connection("gsheets", type=GSheetsConnection)# --- WHATSAPP FONKSİYONU ---def whatsapp_link_olustur(tel, mesaj):    tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")    if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]    elif not tel_str.startswith("90"): tel_str = "90" + tel_str    encoded_mesaj = urllib.parse.quote(mesaj)    return f"https://wa.me/{tel_str}?text={encoded_mesaj}"# --- YAN MENÜ ---st.sidebar.title("☁️ Çözüm VIP Yönetim")sayfa = st.sidebar.radio("İşlem Seçiniz:", ["Veli Görüşmeleri", "Kasa İşlemleri", "Kurucu Raporu"])# --- 1. SAYFA: VELİ GÖRÜŞMELERİ ---if sayfa == "Veli Görüşmeleri":    st.header("📞 Veli Görüşme Kayıt")        # HATA YAKALAYICI: Sayfayı okumaya çalış, boşsa yeni tablo oluştur    try:        existing_data = conn.read(spreadsheet=URL, worksheet="gorusmeler")    except:        existing_data = pd.DataFrame(columns=["Tarih", "Ad Soyad", "Telefon", "Konu", "Durum", "Notlar"])        with st.form("veli_formu", clear_on_submit=True):        col1, col2 = st.columns(2)        with col1:            v_ad = st.text_input("Veli / Öğrenci Ad Soyad")            v_tel = st.text_input("Telefon Numarası")        with col2:            v_konu = st.selectbox("Konu", ["Yeni Kayıt", "YKS Hazırlık", "LGS Hazırlık", "Rehberlik", "Taksit", "Diğer"])            v_durum = st.selectbox("Durum", ["Beklemede", "Olumlu", "Kayıt Tamamlandı", "İptal"])                v_not = st.text_area("Detaylar")        submit = st.form_submit_button("Kaydet ve Sayfaya İşle")            if submit:        if v_ad and v_tel:            new_row = pd.DataFrame([{                "Tarih": datetime.now().strftime("%Y-%m-%d %H:%M"),                "Ad Soyad": v_ad,                "Telefon": v_tel,                "Konu": v_konu,                "Durum": v_durum,                "Notlar": v_not            }])            updated_df = pd.concat([existing_data, new_row], ignore_index=True)            conn.update(spreadsheet=URL, worksheet="gorusmeler", data=updated_df)                        st.success(f"✅ {v_ad} başarıyla Google Sheets'e kaydedildi!")                        # WhatsApp Mesajı            mesaj = f"Sayın {v_ad}, bugün Bostanlı Çözüm VIP Kurs Merkezi'nde yapmış olduğumuz görüşme için teşekkür ederiz."            wa_link = whatsapp_link_olustur(v_tel, mesaj)            st.markdown(f'<a href="{wa_link}" target="_blank"><button style="background-color:#25D366;color:white;border:none;padding:12px;border-radius:8px;cursor:pointer;font-weight:bold;">🟢 Veliye WhatsApp Mesajı Gönder</button></a>', unsafe_allow_html=True)        else:            st.warning("Lütfen Ad Soyad ve Telefon kısımlarını doldurun.")# --- 2. SAYFA: KASA İŞLEMLERİ ---elif sayfa == "Kasa İşlemleri":    st.header("💰 Gelir / Gider Girişi")        try:        existing_kasa = conn.read(spreadsheet=URL, worksheet="kasa")    except:        existing_kasa = pd.DataFrame(columns=["Tarih", "Tip", "Kategori", "Miktar", "Detay"])    with st.form("kasa_formu", clear_on_submit=True):        k_tip = st.radio("İşlem Tipi", ["Gelir (Tahsilat)", "Gider (Ödeme)"])        k_kat = st.selectbox("Kategori", ["Kayıt", "Kitap", "Kira", "Maaş", "Fatura", "Reklam", "Diğer"])        k_tutar = st.number_input("Tutar (TL)", min_value=0.0, step=100.0)        k_detay = st.text_input("Açıklama")        k_submit = st.form_submit_button("Kasaya İşle")            if k_submit:        new_kasa_row = pd.DataFrame([{            "Tarih": datetime.now().strftime("%Y-%m-%d"),            "Tip": k_tip,            "Kategori": k_kat,            "Miktar": k_tutar,            "Detay": k_detay        }])        updated_kasa = pd.concat([existing_kasa, new_kasa_row], ignore_index=True)        conn.update(spreadsheet=URL, worksheet="kasa", data=updated_kasa)        st.success("💰 İşlem Google Sheets tablosuna başarıyla eklendi.")# --- 3. SAYFA: KURUCU RAPORU ---elif sayfa == "Kurucu Raporu":    st.header("📊 Günlük Rapor")    secilen_tarih = st.date_input("Tarih Seç", datetime.now())    t_str = secilen_tarih.strftime("%Y-%m-%d")        try:        g_df = conn.read(spreadsheet=URL, worksheet="gorusmeler")        k_df = conn.read(spreadsheet=URL, worksheet="kasa")                # Seçilen tarihe göre filtrele        g_bugun = g_df[g_df['Tarih'].str.contains(t_str, na=False)]        k_bugun = k_df[k_df['Tarih'] == t_str]                gelir = k_bugun[k_bugun['Tip'] == 'Gelir (Tahsilat)']['Miktar'].sum()        gider = k_bugun[k_bugun['Tip'] == 'Gider (Ödeme)']['Miktar'].sum()                col1, col2, col3 = st.columns(3)        col1.metric("Görüşme", len(g_bugun))        col2.metric("Gelir", f"{gelir:,.0f} TL")        col3.metric("Gider", f"{gider:,.0f} TL")                rapor_metni = f"*📌 BOSTANLI ÇÖZÜM RAPORU ({t_str})*\n\n📞 Görüşme: {len(g_bugun)}\n💰 Gelir: {gelir:,.0f} TL\n💸 Gider: {gider:,.0f} TL\n📈 Net: {gelir-gider:,.0f} TL"        st.info(rapor_metni)                kurucu_link = whatsapp_link_olustur("905492551912", rapor_metni)        st.markdown(f'<a href="{kurucu_link}" target="_blank"><button style="background-color:#075E54;color:white;border:none;padding:15px;border-radius:10px;cursor:pointer;width:100%;font-weight:bold;">📲 Raporu Kurucuya WhatsApp ile Gönder</button></a>', unsafe_allow_html=True)    except:        st.error("Henüz veri bulunamadı veya tabloya ulaşılamıyor.")